#!/bin/bash
set -e -x

app_bin=./wasm/ebtc.wasm
charms app vk $app_bin

export app_vk=$(charms app vk $app_bin)

# UTXO you're spending (1st input determines the NFT identity)
export in_utxo_0="22ac8af70480f31287b9e3a9884e88af32dee0f365ff184385f71ccece93b3df:0"
prev_tx_0=""

# compute app_id from the 1st input UTXO ID
export app_id=$(hashutxoid ${in_utxo_0})

# change output
export addr_0="bc1q6fyytfqlp0hxlm2vys8smdkk6097yr66fsljyr"
export dest_0=$(charms util dest --addr ${addr_0})
export amount_0=300

change_adddress=bc1qvsrmdllfupgzr442duw2rduy59c576kwhefplt

cat ./spells/mint-nft.yaml | envsubst | charms spell prove \
  --prev-txs=${prev_tx_0} \
  --app-bins=${app_bin} \
  --change-address=${change_adddress}
